args.sparql:
PREFIX wd: http://www.wikidata.org/entity/
PREFIX wdt: http://www.wikidata.org/prop/direct/

SELECT ?date
WHERE {
  ?season wdt:P31 wd:Q11995151 ;
          wdt:P2550 wd:Q18756 ;
          wdt:P580 ?season_start .
  ?season wdt:P2875 ?stage .
  ?stage wdt:P31 wd:Q11564376 .
  ?stage wdt:P585 ?date .
}
ORDER BY DESC(?season_start)
LIMIT 1

